// Without function — repetitive
console.log(2 * 3.14 * 5);  // area of circle r=5
console.log(2 * 3.14 * 8);  // area of circle r=8

// With function — reusable
function circleArea(r) {
    return 2 * 3.14 * r;
}
console.log(circleArea(5));  // 31.4
console.log(circleArea(8));  // 50.24

// Function declaration (hoisted)
function greet(name) {          // name = parameter
    return `Hello, ${name}!`;
}
console.log(greet('Alice'));    // 'Alice' = argument
// Output: Hello, Alice!

// Function expression (NOT hoisted)
const square = function(n) {
    return n * n;
};
console.log(square(4));  // 16

// Calling before declaration — works for declarations
console.log(add(2, 3));  // 5 — works due to hoisting
function add(a, b) { return a + b; }

// Single parameter
const double = n => n * 2;
console.log(double(5));      // 10

// Multiple parameters
function power(base, exp) {
    return Math.pow(base, exp);
}
console.log(power(2, 10));   // 1024

// N parameters using rest
function sum(...nums) {
    return nums.reduce((acc, n) => acc + n, 0);
}
console.log(sum(1, 2, 3, 4, 5)); // 15
console.log(sum(10, 20));         // 30

