// Custom error
class ValidationError extends Error {
    constructor(message, field) {
        super(message);
        this.name    = 'ValidationError';
        this.field   = field;
    }
}

function validateAge(age) {
    if (typeof age !== 'number') {
        throw new ValidationError('Age must be a number', 'age');
    }
    if (age < 0 || age > 150) {
        throw new ValidationError('Age out of range', 'age');
    }
    return true;
}

try {
    validateAge('twenty');
} catch (e) {
    if (e instanceof ValidationError) {
        console.log(`Field: ${e.field}, Error: ${e.message}`);
    }
}

class NetworkError extends Error {
    constructor(message, statusCode) {
        super(message);
        this.name       = 'NetworkError';
        this.statusCode = statusCode;
    }
}

class AuthError extends Error {
    constructor(message) {
        super(message);
        this.name = 'AuthError';
    }
}

async function fetchData(url) {
    try {
        const res = await fetch(url);
        if (res.status === 401) throw new AuthError('Unauthorized');
        if (!res.ok) throw new NetworkError('Request failed', res.status);
        return await res.json();
    } catch (err) {
        if (err instanceof AuthError) {
            redirectToLogin();   // handle auth errors here
        } else {
            throw err;           // re-throw — let caller handle
        }
    }
}

